def _package_root():
    script_file = globals().get("__file__")
    if not script_file:
        raise RuntimeError(
            "The v0.6 importer must run from its extracted .py file so bundled WAV paths "
            "can be resolved safely."
        )
    return Path(script_file).resolve().parent


def _source_audio_file(audio_import):
    root = _package_root()
    source = (root / audio_import["source_relative_path"]).resolve()
    try:
        source.relative_to(root)
    except ValueError as exc:
        raise RuntimeError(
            f"Audio source escapes the extracted import package: {source}"
        ) from exc
    if not source.is_file():
        raise RuntimeError(f"Bundled WAV file does not exist: {source}")
    digest = sha256(source.read_bytes()).hexdigest()
    if digest != audio_import["source_sha256"]:
        raise RuntimeError(f"Bundled WAV checksum does not match: {source}")
    return source


def _preflight_import():
    targets = [
        f"{scene['package_path']}/{scene['asset_name']}"
        for scene in PLAN["sequences"]
    ]
    targets.extend(item["asset_path"] for item in PLAN["audio_imports"])
    if len(set(targets)) != len(targets):
        raise RuntimeError("Import plan contains duplicate Unreal asset targets.")

    conflicts = [
        target
        for target in targets
        if unreal.EditorAssetLibrary.does_asset_exist(target)
    ]
    if conflicts:
        formatted = "\n".join(f"- {target}" for target in conflicts)
        raise RuntimeError(
            "Refusing to replace existing assets. Delete or relocate them intentionally:\n"
            f"{formatted}"
        )

    for audio_import in PLAN["audio_imports"]:
        _source_audio_file(audio_import)


def _import_audio_assets():
    if not PLAN["audio_imports"]:
        return []

    tasks = []
    for audio_import in PLAN["audio_imports"]:
        task = unreal.AssetImportTask()
        task.set_editor_property("filename", str(_source_audio_file(audio_import)))
        task.set_editor_property("destination_path", audio_import["destination_path"])
        task.set_editor_property("destination_name", audio_import["asset_name"])
        task.set_editor_property("automated", True)
        task.set_editor_property("replace_existing", False)
        task.set_editor_property("save", True)
        tasks.append(task)

    unreal.AssetToolsHelpers.get_asset_tools().import_asset_tasks(tasks)
    imported = []
    for audio_import in PLAN["audio_imports"]:
        imported.append(_load_sound(audio_import["asset_path"]))
        unreal.log(
            f"CutSceneAI imported {audio_import['source_relative_path']} -> "
            f"{audio_import['asset_path']}"
        )
    return imported


def _vector(data):
    return unreal.Vector(float(data["x"]), float(data["y"]), float(data["z"]))


def _rotator(data):
    return unreal.Quat(
        float(data["x"]),
        float(data["y"]),
        float(data["z"]),
        float(data["w"]),
    ).rotator()


def _set_transform(actor, data):
    actor.set_actor_location(_vector(data["location_cm"]), False, True)
    actor.set_actor_rotation(_rotator(data["rotation"]), True)
    actor.set_actor_scale3d(_vector(data["scale"]))


def _load_class(class_path):
    actor_class = unreal.load_class(None, class_path)
    if actor_class is None:
        raise RuntimeError(f"Unable to load Unreal class: {class_path}")
    return actor_class


def _load_static_mesh(asset_path):
    static_mesh = unreal.EditorAssetLibrary.load_asset(asset_path)
    if not isinstance(static_mesh, unreal.StaticMesh):
        raise RuntimeError(f"Static mesh could not be loaded: {asset_path}")
    return static_mesh


def _load_skeletal_mesh(asset_path):
    skeletal_mesh = unreal.EditorAssetLibrary.load_asset(asset_path)
    if not isinstance(skeletal_mesh, unreal.SkeletalMesh):
        raise RuntimeError(f"Skeletal mesh could not be loaded: {asset_path}")
    return skeletal_mesh


def _load_animation(asset_path):
    animation = unreal.EditorAssetLibrary.load_asset(asset_path)
    if not isinstance(animation, unreal.AnimSequenceBase):
        raise RuntimeError(f"Animation could not be loaded: {asset_path}")
    return animation


def _load_sound(asset_path):
    sound = unreal.EditorAssetLibrary.load_asset(asset_path)
    if not isinstance(sound, unreal.SoundBase):
        raise RuntimeError(f"Sound could not be loaded: {asset_path}")
    return sound


def _configure_static_mesh(actor, static_mesh, asset_path):
    component = actor.get_editor_property("static_mesh_component")
    if component is None:
        raise RuntimeError(f"StaticMeshActor has no Static Mesh Component: {asset_path}")
    component.set_static_mesh(static_mesh)


def _configure_skeletal_mesh(actor, skeletal_mesh, asset_path):
    component = actor.get_editor_property("skeletal_mesh_component")
    if component is None:
        raise RuntimeError(
            f"SkeletalMeshActor has no Skeletal Mesh Component: {asset_path}"
        )
    component.set_skeletal_mesh_asset(skeletal_mesh)


def _resolve_live_bound_object(sequence, binding, object_type):
    unreal.LevelSequenceEditorBlueprintLibrary.force_update()
    binding_id = sequence.get_binding_id(binding)
    return next(
        (
            item
            for item in unreal.LevelSequenceEditorBlueprintLibrary.get_bound_objects(
                binding_id
            )
            if isinstance(item, object_type)
        ),
        None,
    )


def _remove_default_transform_tracks(binding):
    for track in binding.find_tracks_by_exact_type(
        unreal.MovieScene3DTransformTrack
    ):
        binding.remove_track(track)


def _configure_static_mesh_spawnable(
    sequence,
    subsystem,
    binding,
    binding_id,
    display_name,
    transform,
    asset_path,
):
    static_mesh = _load_static_mesh(asset_path)
    template = binding.get_object_template()
    live_actor = _resolve_live_bound_object(
        sequence, binding, unreal.StaticMeshActor
    )
    targets = []
    if isinstance(template, unreal.StaticMeshActor):
        targets.append(template)
    if live_actor is not None and live_actor is not template:
        targets.append(live_actor)
    if not targets:
        raise RuntimeError(f"Unable to resolve StaticMeshActor spawnable: {binding_id}")
    for target in targets:
        target.set_actor_label(display_name)
        _set_transform(target, transform)
        _configure_static_mesh(target, static_mesh, asset_path)
    if live_actor is not None:
        subsystem.save_default_spawnable_state(binding)


